// Reference dataset types — the single source of truth shared by the website
// reference pages (web/docs) and the kapi-desktop Storybook fixtures.
//
// Generated by scripts/gen-refs (Go). Keep the Go side in sync with
// scripts/gen-refs/model.go.
//
// The schema/doc types below are inlined (not imported from
// @neokapi/ui-primitives) so this package stays dependency-free and portable
// to consumers outside the workspace. They MUST stay structurally identical to
// packages/ui/src/components/schema-form/types.ts so an entry's `schema` is
// assignable to SchemaForm's `schema` prop and `doc.parameters` to `paramDocs`.

// ── Schema-form types (mirror of @neokapi/ui-primitives schema-form/types) ──

export interface ComponentSchema {
  $id?: string;
  $version?: string;
  title: string;
  description?: string;
  type: string;
  formatMeta?: FormatMeta;
  toolMeta?: ToolMeta;
  presets?: Record<string, Record<string, unknown>>;
  "ui:groups"?: ParameterGroup[];
  properties?: Record<string, PropertySchema>;
}

export interface FormatMeta {
  id: string;
  extensions?: string[];
  mimeTypes?: string[];
}

export interface ToolMeta {
  id?: string;
  displayName?: string;
  description?: string;
  category?: string;
  inputs?: string[];
  outputs?: string[];
  tags?: string[];
  requires?: string[];
}

export interface ParameterGroup {
  id: string;
  label: string;
  description?: string;
  collapsible?: boolean;
  collapsed?: boolean;
  icon?: string;
  fields: string[];
}

export type ConditionExpr =
  | { field: string; eq: unknown }
  | { field: string; empty: boolean }
  | { all: ConditionExpr[] }
  | { any: ConditionExpr[] }
  | { not: ConditionExpr };

export interface LayoutHints {
  hideLabel?: boolean;
  vertical?: boolean;
  columns?: number;
}

export interface PropertySchema {
  type: string;
  title?: string;
  description?: string;
  default?: unknown;
  deprecated?: boolean;
  enum?: unknown[];
  minimum?: number;
  maximum?: number;
  minLength?: number;
  maxLength?: number;
  options?: { value: unknown; label: string }[];
  "ui:widget"?: string;
  "ui:widget-options"?: Record<string, unknown>;
  "ui:placeholder"?: string;
  "ui:presets"?: Record<string, unknown>;
  "ui:visible"?: ConditionExpr;
  "ui:enabled"?: ConditionExpr;
  "ui:layout"?: LayoutHints;
  "ui:enum-labels"?: Record<string, string>;
  "ui:enum-descriptions"?: Record<string, string>;
  "ui:order"?: number;
  "ui:deprecated-message"?: string;
  "ui:introduced-in"?: string;
  "x-okapi-flatten-path"?: string;
  "x-okapi-format"?: string;
  "x-path"?: {
    type?: string;
    role?: string;
    resourceKind?: string;
    accepts?: string[];
    browseTitle?: string;
    filters?: Array<{ name: string; extensions: string }>;
  };
  properties?: Record<string, PropertySchema>;
  additionalProperties?: PropertySchema | boolean;
  items?: PropertySchema;
  prefixItems?: PropertySchema[];
  minItems?: number;
  maxItems?: number;
  oneOf?: PropertySchema[];
}

/** Per-parameter documentation; handed to SchemaForm's `paramDocs` unchanged. */
export interface ToolDocParam {
  description?: string;
  help?: string;
  notes?: string[];
  introducedIn?: string;
  dependsOn?: Array<{ property: string; condition: string }>;
  values?: string;
  examples?: string[];
  seeAlso?: string;
}

// ── Reference dataset types ─────────────────────────────────────────────────

/** Which engine provides an entry. */
export type ReferenceSource = "built-in" | "okapi";

/** Whether an entry is a data format or a processing tool. */
export type ReferenceKind = "format" | "tool";

/** A worked configuration example. */
export interface ReferenceExample {
  title: string;
  description?: string;
  /** Fenced YAML configuration snippet. */
  config?: string;
  input?: string;
  output?: string;
}

/** Rich reference documentation for an entry. `parameters` is handed to
 *  SchemaForm as its `paramDocs` prop unchanged. */
export interface ReferenceDoc {
  overview?: string;
  parameters?: Record<string, ToolDocParam>;
  limitations?: string[];
  processingNotes?: string[];
  examples?: ReferenceExample[];
  wikiUrl?: string;
}

/** One format or tool in the reference dataset. */
export interface ReferenceEntry {
  id: string;
  source: ReferenceSource;
  kind: ReferenceKind;
  displayName: string;
  description?: string;

  // Format-only metadata.
  extensions?: string[];
  mimeTypes?: string[];
  hasReader?: boolean;
  hasWriter?: boolean;

  // Tool-only metadata.
  category?: string;
  inputs?: string[];
  outputs?: string[];
  tags?: string[];
  requires?: string[];
  cardinality?: string;
  aliases?: string[];

  /** The schema consumed verbatim by the shared SchemaForm renderer. */
  schema?: ComponentSchema;
  doc?: ReferenceDoc;
  presets?: Record<string, Record<string, unknown>>;
}

/** Top-level document for formats.json / tools.json. */
export interface ReferenceDataset {
  generatedAt: string;
  kind: ReferenceKind;
  entries: ReferenceEntry[];
}

/** One missing-metadata finding. */
export interface ReferenceGap {
  kind: ReferenceKind;
  source: ReferenceSource;
  id: string;
  field: string;
  detail: string;
}

/** Top-level document for reference-gaps.json. */
export interface ReferenceGapReport {
  generatedAt: string;
  summary: Record<string, number>;
  gaps: ReferenceGap[];
}
